1	// Static packaging artifact tests — no build tools required, no FUSE mount.
2	//
3	// Verifies that build.sh and PKGBUILD contain the structural elements that
4	// make the AppImage work at runtime: ORT library bundling, AppRun LD_LIBRARY_PATH,
5	// and the onnxruntime runtime dependency declaration.
6	
7	use std::fs;
8	use std::path::Path;
9	
10	fn project_root() -> std::path::PathBuf {
11	    Path::new(env!("CARGO_MANIFEST_DIR")).to_path_buf()
12	}
13	
14	fn read_file(rel: &str) -> String {
15	    let path = project_root().join(rel);
16	    fs::read_to_string(&path).unwrap_or_else(|e| panic!("cannot read {rel}: {e}"))
17	}
18	
19	#[test]
20	fn build_sh_copies_ort_so_into_appdir_lib() {
21	    let src = read_file("packaging/appimage/build.sh");
22	    assert!(
23	        src.contains("libonnxruntime.so") && src.contains("usr/lib/libonnxruntime.so"),
24	        "build.sh must copy libonnxruntime.so into usr/lib/; got:\n{src}"
25	    );
26	}
27	
28	#[test]
29	fn build_sh_discovers_ort_via_env_var_fallback() {
30	    let src = read_file("packaging/appimage/build.sh");
31	    assert!(
32	        src.contains("ORT_DYLIB_PATH"),
33	        "build.sh must fall back to ORT_DYLIB_PATH for ORT discovery; got:\n{src}"
34	    );
35	}
36	
37	#[test]
38	fn build_sh_writes_apprun_with_ld_library_path() {
39	    let src = read_file("packaging/appimage/build.sh");
40	    assert!(
41	        src.contains("AppRun") && src.contains("LD_LIBRARY_PATH"),
42	        "build.sh must write AppRun and set LD_LIBRARY_PATH; got:\n{src}"
43	    );
44	}
45	
46	#[test]
47	fn build_sh_gates_linuxdeploy_on_command_v() {
48	    let src = read_file("packaging/appimage/build.sh");
49	    assert!(
50	        src.contains("command -v linuxdeploy"),
51	        "build.sh must gate linuxdeploy invocation on command -v; got:\n{src}"
52	    );
53	}
54	
55	#[test]
56	fn pkgbuild_declares_onnxruntime_runtime_dep() {
57	    let src = read_file("packaging/PKGBUILD");
58	    assert!(
59	        src.contains("onnxruntime"),
60	        "PKGBUILD must list onnxruntime in depends; got:\n{src}"
61	    );
62	}
63	
64	#[test]
65	fn pkgbuild_has_clang_in_makedepends() {
66	    let src = read_file("packaging/PKGBUILD");
67	    // clang is required at build time by bindgen/clang-sys (transitive dep of sherpa-onnx-sys)
68	    let has_makedepends = src.lines().any(|l| l.contains("makedepends="));
69	    let has_clang = src.contains("'clang'");
70	    assert!(
71	        has_makedepends && has_clang,
72	        "PKGBUILD must list 'clang' inside makedepends=; got:\n{src}"
73	    );
74	}
75	
76	#[test]
77	fn pkgbuild_includes_sherpa_onnx_offline_source() {
78	    let src = read_file("packaging/PKGBUILD");
79	    assert!(
80	        src.contains("sherpa-onnx-v1.12.39-linux-x64-shared-lib.tar.bz2"),
81	        "PKGBUILD must include the sherpa-onnx 1.12.39 prebuilt archive as a source entry; got:\n{src}"
82	    );
83	}
84	
85	#[test]
86	fn pkgbuild_sets_sherpa_onnx_archive_dir() {
87	    let src = read_file("packaging/PKGBUILD");
88	    assert!(
89	        src.contains("SHERPA_ONNX_ARCHIVE_DIR"),
90	        "PKGBUILD must export SHERPA_ONNX_ARCHIVE_DIR so the build script picks up the local archive; got:\n{src}"
91	    );
92	}
93	
94	#[test]
95	fn release_yml_uploads_source_tarball() {
96	    let src = read_file(".github/workflows/release.yml");
97	    assert!(
98	        src.contains("git archive") && src.contains("vibe-attack-"),
99	        "release.yml must invoke git archive and reference a vibe-attack-*.tar.gz glob; got:\n{src}"
100	    );
101	}
